// Espera msg.payload como objeto JSON
const p = msg.payload;
const t = p?.aht?.t;
const rh = p?.aht?.rh;
const ts = p?.ms ?? Date.now(); // ms del ESP32 o timestamp local

let out = [];

if (typeof t === "number") {
  out.push({
    topic: "temp",
    payload: t,
    timestamp: ts
  });
}

if (typeof rh === "number") {
  out.push({
    topic: "rh",
    payload: rh,
    timestamp: ts
  });
}

return [out];

const p = msg.payload;
const ens = p?.ens;

if (!ens) return null;

const ts = p?.ms ?? Date.now();

let out = [];

// TVOC (ppb)
if (typeof ens.tvoc === "number") {
    out.push({
        topic: "TVOC (ppb)",
        payload: ens.tvoc,
        timestamp: ts
    });
}

// eCO2 (ppm)
if (typeof ens.eco2 === "number") {
    out.push({
        topic: "eCO2 (ppm)",
        payload: ens.eco2,
        timestamp: ts
    });
}

return [out];

